INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00472', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '再徙北城，所居止三席地，其左無壁，覆之以苫。日常使姊守舍，攜中及妹，傫然丐於親故，率日不 得一食；歸則藉藁於地。每冬夜號寒，母子相擁，不自意全濟，比見晨光，則欣然有生望焉。迨中入 學宮，游藝四方，稍致甘旨之養。母百病交攻，綿歷歲年，竟致不起。嗚呼痛哉！（汪中〈先母鄒孺 人靈表〉） 上文內容之書寫，未包括下列何者？', '["居住", "交通", "飲食", "臥寢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00473', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '承上題，汪中對於母親，其心情可用下列何者說明？', '["兒孫自有兒孫福", "養兒方知父母恩", "天下無不是父母", "子欲養而親不待"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00474', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '《格言聯璧》：「居處必先精勤，乃能閒暇。凡事務求停妥，然後逍遙。」 上文揭示的道理，與下列何者最為相近？', '["真積力久則入", "業精於勤，荒於嬉", "凡事豫則立，不豫則廢", "淡泊以明志，寧靜以致遠"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00475', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '今斯地初開，雖風水屢洊而不為異，五患水，三患颱，而民不饑，無有散亂，何也？民皆手創其業， 艱難未忘，室家未阜，而不敢有淫慝之思也。雖然，吾特有懼焉，懼夫更十年後，地利盡闢，戶口殷 富，老者死而少者壯，民惟見其樂而不見其艱也，則將有滋為淫佚，而樂於兇悍暴亂者，人禍之興， 吾安知其所極耶？（姚瑩〈噶瑪蘭颱異記〉）根據上文，下列選項何者最貼近作者意旨？', '["移民墾荒剽悍勤奮，無畏天災人禍", "地盡其利，才能使民安居致富，得享豐足生活", "提醒移民務必抱持人定勝天的觀念，才能安居樂業", "警示後人不可因漸趨安樂而迷失本性，否則必將帶來災害"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00476', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「親愛的孩子：來信收到了，你說，你越讀得多，越聽得多，越糊塗了：這是智慧之門將要開的信號， 千萬不要灰心。諺語說：『公說公有理，婆說婆有理』，世間這樣的公婆實在太多了。因為他（她）們 的立場不同，考察事物的角度不同，偏見是免不了的。……我們在日常生活中，到處都會碰到這類的 情形，要是聽公說了就信了，聽婆說了又信了，自己一點不懷疑，不想去追尋公婆的矛盾所在，不想 徹底去追求真假與是非，馬馬虎虎被牽著鼻子走的話，那才是真正的糊塗蟲。」 根據上文，下列選項何者與作者主張最為相近？', '["一切唯心造", "真理不辯自明", "盡信書不如無書", "偏見是無知的產物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00477', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '承上題，作者將「越讀得多，越聽得多，越糊塗了」視為智慧之門將要開的信號，其意在於表達：', '["福禍相倚，善惡互見", "困頓蟄伏，破繭重生", "見多識廣，心智澄明", "格物窮理，審問慎思"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00478', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「實驗者給打坐一萬小時以上的大師聽砲彈聲、嬰兒婦孺的哭叫聲，同時掃瞄他們的大腦。結果發現 他們的聽覺皮質有活化，表示他們有聽見，但是管情緒的杏仁核及管理智決策的前額葉皮質都沒有活 化，表示他們可以把情緒放一邊不去理它。所以沒人使你不快樂，是你自己使你不快樂。」 根據上文，下列選項何者敘述錯誤？', '["大腦能同時處理聽覺與情緒", "打坐是淨化心靈的良方之一", "不快樂往往是別人所造成的", "應該要學會控制自己的情緒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00479', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '下列文句，語言表述合乎邏輯的選項是：', '["現在能夠吹奏排簫的人，已經是汗牛充棟寥寥可數了", "經過一番長途跋涉，終於順利抵達位居深山的友人家", "他才華普通，作品並無過人之處，我們難以望其項背", "雨花石色彩豐富，形態各異，巧奪天工，具收藏價值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00480', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「生下來不被愛的人，可以打破不被愛就不能愛的魔咒，學著關愛與付出，如果遇到挫折，嘗試調整 與修正，漸漸明瞭什麼是愛，而且有能力去愛，從□□者蛻變成□□者。」 上文空缺處最適合填入的是：', '["無心，多情", "內向，外向", "匱乏，給予", "仁慈，睿智"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00481', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「面對這個比人類歷史長遠幾萬倍的沙岸時，我只感覺自己猶若針尖，甚至於子虛。」 下列選項，其涵意與上文旨意最相近的是：', '["蝸角虛名，蠅頭微利", "百川異源，而皆歸於海", "上無片瓦，下無插針之地", "寄蜉蝣於天地，渺滄海之一粟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
